import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Test for the issue: "Formatting enum class with member definition and missing trailing commas causes rule
 * violations on first run"
 */
class TrailingCommaOnDeclarationSiteRuleIssueTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnDeclarationSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
                // Also test that no-semi rule doesn't complain
                RuleProvider { NoSemicolonsRule() },
            ),
        )

    @Test
    fun `Issue - Given an enum class with member definitions and missing trailing comma then it should be added without causing subsequent violations`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class TestEnum() {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 6, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue - Given an enum class with function definition and missing trailing comma then it should be added without causing subsequent violations`() {
        val code =
            """
            enum class Shape {
                SQUARE,
                TRIANGLE;

                fun print() = name()
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class Shape {
                SQUARE,
                TRIANGLE,
                ;

                fun print() = name()
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 13, "Missing trailing comma before \";\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue - Given an enum class with property definition and missing trailing comma then it should be added without causing subsequent violations`() {
        val code =
            """
            enum class Color {
                RED,
                GREEN,
                BLUE;

                val isWarm: Boolean = false
            }
            """.trimIndent()
        val formattedCode =
